       pt.teacher_id, pt.student_limit, pt.team_limit,
       pt.status, pt.open_status, pt.create_time, pt.update_time,
       t.teacher_name
FROM project_topic pt
LEFT JOIN teacher t ON pt.teacher_id = t.teacher_id
WHERE pt.is_deleted = #{isDeleted}

